-- Label border-spillover events with their country (fix-border-event-enrichment).
--
-- Problem: the NG/GH ingestion bounding boxes overhang into neighbouring
-- countries, so border wildfires from those neighbours are ingested and
-- correctly kept (fix-ingest-bbox-validation) -- but the enrichment trigger
-- matches only adm_level = 1 (state) polygons, and admin_boundaries held
-- Nigeria + Ghana only. Such events landed with country_name AND state_name
-- NULL (7 of 43 on staging: Cameroon, Benin, Niger).
--
-- Fix:
--   1. Trigger gains an ADM0 (country) fallback that runs only when the ADM1
--      lookup matched no state -- sets country_name, leaves state_name NULL.
--   2. Load ADM0 national outlines for the 7 countries whose territory
--      intersects either ingestion box: Benin, Niger, Chad, Cameroon (NG box)
--      and Cote d'Ivoire, Burkina Faso, Togo (GH box).
--   3. Backfill already-stored events so the current NULL rows pick up country.
--
-- Source: geoBoundaries gbOpen ADM0 (simplified), EPSG:4326, further reduced
-- with ST_SimplifyPreserveTopology(0.01deg) -- country-level containment needs
-- no finer precision, and the fallback only ever sees points already outside
-- every NG/GH state. Regenerate via the geoBoundaries API rather than reading
-- the GeoJSON line-by-line.
--
-- Enrichment-only: ingestion is driven by DefaultCountries and never reads
-- admin_boundaries, so this changes labelling, not what is ingested. The
-- ingestion bboxes and 000011's frozen purge predicate are untouched.

BEGIN;

-- 1. Enrichment trigger: ADM1 first, ADM0 country fallback second.
CREATE OR REPLACE FUNCTION trg_enrich_event_location()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.geom IS NOT NULL THEN
        -- Prefer the most specific administrative level: match a state (ADM1).
        SELECT adm_name, country_name
        INTO NEW.state_name, NEW.country_name
        FROM admin_boundaries
        WHERE adm_level = 1
          AND ST_Intersects(NEW.geom, geom)
        ORDER BY ST_Area(geom::geography) ASC
        LIMIT 1;

        -- Fall back to country (ADM0) when no state matched. Labels border
        -- spillover from neighbours we ingest but hold no states for, and
        -- rescues any point that falls in a gap between real ADM1 polygons.
        -- state_name is deliberately left NULL -- we do not invent a state.
        IF NEW.country_name IS NULL THEN
            SELECT country_name
            INTO NEW.country_name
            FROM admin_boundaries
            WHERE adm_level = 0
              AND ST_Intersects(NEW.geom, geom)
            ORDER BY ST_Area(geom::geography) ASC
            LIMIT 1;
        END IF;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS enrich_event_location_trigger ON events;
CREATE TRIGGER enrich_event_location_trigger
BEFORE INSERT OR UPDATE OF geom ON events
FOR EACH ROW
EXECUTE FUNCTION trg_enrich_event_location();

-- 2. Neighbour ADM0 national outlines (country-level labelling only).
DELETE FROM admin_boundaries WHERE country_code IN ('BJ', 'NE', 'TD', 'CM', 'CI', 'BF', 'TG');
INSERT INTO admin_boundaries (country_code, country_name, adm_level, adm_name, geom) VALUES
